\usetikzlibrary{arrows.meta}
\begin{tikzpicture}[scale=1.2]
  % Grid
  \draw[gray!20, thin] (-3,-1) grid (4,6);
  % Axes
  \draw[very thick, -{Stealth[length=3mm]}] (-3.5,0) -- (4.5,0) node[right, font=\normalsize] {$x$};
  \draw[very thick, -{Stealth[length=3mm]}] (0,-1.5) -- (0,6.5) node[above, font=\normalsize] {$y$};
  % Tick labels
  \foreach \x in {-3,-2,-1,1,2,3,4} {
    \node[below=3pt, font=\footnotesize] at (\x, 0) {\x};
  }
  \foreach \y in {1,2,3,4,5,6} {
    \node[left=3pt, font=\footnotesize] at (0, \y) {\y};
  }
  \node[below left=3pt, font=\footnotesize] at (0,0) {0};
  % Plotted points
  \fill[red] (2, 3) circle (0.1);
  \node[above right=4pt, red, font=\large, fill=white, inner sep=2pt] at (2, 3) {A(2, 3)};
  \fill[blue] (-1, 4) circle (0.1);
  \node[above left=4pt, blue, font=\large, fill=white, inner sep=2pt] at (-1, 4) {B(-1, 4)};
\end{tikzpicture}
